function toBaseK(num, k) {
    let baseKNum = "";
    while (num > 0) {
        baseKNum = (num % k) + baseKNum;
        num = Math.floor(num / k);
    }
    return baseKNum;
}

function isKMirror(num, k) {
    const base10Num = num.toString();
    const baseKNum = toBaseK(num, k);
    return base10Num === base10Num.split('').reverse().join('') &&
           baseKNum === baseKNum.split('').reverse().join('');
}

function sumKMirrorNumbers(k, n) {
    let sum = 0;
    let num = 0;
    while (n > 0) {
        if (isKMirror(num, k)) {
            sum += num;
            n--;
        }
        num++;
    }
    return sum;
}
```


