public static String toBaseK(int num, int k) {
    StringBuilder baseKNum = new StringBuilder();
    while (num > 0) {
        baseKNum.append(num % k);
        num /= k;
    }
    return baseKNum.toString();
}

public static boolean isKMirror(int num, int k) {
    String base10Num = Integer.toString(num);
    String baseKNum = toBaseK(num, k);
    return (new StringBuilder(base10Num).reverse().toString().equals(base10Num)) &&
           (new StringBuilder(baseKNum).reverse().toString().equals(baseKNum));
}

public static int sumKMirrorNumbers(int k, int n) {
    int sum = 0;
    int num = 0;
    while (n > 0) {
        if (isKMirror(num, k)) {
            sum += num;
            n--;
        }
        num++;
    }
    return sum;
}
```


